  ('heelevel3-d592fc58-moex-00227', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-110-9b7ab1bb', 'sub-heelevel3-d592fc58-05', NULL, 'single_choice', '甲1、甲2、甲3至甲10等10人，經登記為A區分所有建築物之區分所有人。甲1、甲2、甲3 至甲10等10人依法律規定作成以下規約：甲1得使用A區分所有建築物之頂樓。甲1出賣其專 有部分，移轉其占有於乙，登記乙為A區分所有建築物之區分所有人。乙於受讓時就甲1依該規 約所享有權利一事，不知且非可得而知。下列敘述，何者正確？', '["該規約雖未經登記，但因乙就甲1依該規約所享有權利一事，不知且非可得而知，故得使用A 區分所有建築物之頂樓", "乙就甲1依該規約所享有權利一事，不知且非可得而知，故得使用A區分所有建築物之頂樓", "該規約未經登記，乙因此得使用A區分所有建築物之頂樓", "乙得使用A區分所有建築物之頂樓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:54+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "333", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00228', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-110-9b7ab1bb', 'sub-heelevel3-d592fc58-05', NULL, 'single_choice', '甲登記為A地所有人，於A地上設定20年期限之普通地上權於乙。甲與乙約定，乙每年應支付 甲地租新臺幣15萬元，共計20年地租之約定。某日夜晚，甲於A地上掩埋大量劇毒廢棄物，致 A地受有縱經百年休養亦無法回復，完全不能達原來使用之損害。下列敘述，何者正確？', '["乙得支付未到期之3年分地租後，拋棄其地上權", "乙得支付未到期之1年分地租，拋棄其地上權", "乙得支付未到期2年分之地租，拋棄其地上權", "乙得拋棄其地上權，並免地租支付義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:54+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "333", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00229', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-110-9b7ab1bb', 'sub-heelevel3-d592fc58-05', NULL, 'single_choice', '下列何種請求權之消滅時效為15年？', '["離婚時之剩餘財產差額分配請求權", "判決離婚時之損害賠償請求權", "解除婚約時之損害賠償請求權", "解除婚約時之贈與物返還請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:54+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "333", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00230', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-110-9b7ab1bb', 'sub-heelevel3-d592fc58-05', NULL, 'single_choice', '張大雄與李靜香結婚，並約定妻冠夫姓而成張李靜香，二人生子名為小明，並約定該子從母姓， 小明之姓名應為下列何者？', '["李小明", "張李小明", "李張小明", "張小明"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:54+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "333", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00231', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-110-9b7ab1bb', 'sub-heelevel3-d592fc58-05', NULL, 'single_choice', '甲為A照護中心之代表人，乙受監護之宣告，甲於何種情形，不得為乙之監護人？', '["甲為乙之配偶", "甲為乙之四親等之堂兄", "甲為乙之三親等之姨丈", "甲為乙之女婿"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:54+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "333", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00232', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-110-9b7ab1bb', 'sub-heelevel3-d592fc58-05', NULL, 'single_choice', '下列關於法定繼承人之敘述，何者錯誤？', '["民法第1138條第2款所稱之母，自不包含父所娶之後妻在內", "民法第1138條第3款所稱兄弟姊妹，包括同父異母或同母異父之兄弟姊妹", "養子女對本生父母之遺產，無繼承權", "法定繼承人如喪失我國國籍者，不得繼承被繼承人之遺產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:54+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "333", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00233', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-110-9b7ab1bb', 'sub-heelevel3-d592fc58-05', NULL, 'single_choice', '下列關於繼承權有無之敘述，何者錯誤？', '["繼承開始後，繼承人已取得繼承權", "繼承開始後已取得繼承權，仍可能因變造遺囑而喪失", "繼承開始前喪失繼承權，仍可能因被繼承人宥恕而回復", "對被繼承人重大虐待者，應經被繼承人遺囑表示，始喪失繼承權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:54+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "333", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00234', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-110-9b7ab1bb', 'sub-heelevel3-d592fc58-05', NULL, 'single_choice', '甲因其子乙結婚而贈與乙新臺幣（下同）100 萬元。甲與丙再婚，翌日甲即死亡。甲死亡時有財 產500萬元，對丁負債200萬元。甲之繼承人乙及丙發現甲之遺囑中表示，遺贈甲之母戊250萬 元。下列敘述，何者正確？', '["丙受有特留分100萬元保障", "乙得對戊主張扣減遺贈50萬元", "乙的特留分較丙多50萬元", "戊得向乙丙主張酌給遺產權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:54+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "333", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
  ('heelevel3-d592fc58-moex-00235', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-110-d3ff7f6b', 'sub-heelevel3-d592fc58-02', NULL, 'essay', '請評斷下列敘述為「真確」或「錯誤」，並對於你所做的評斷加以解釋說
